SELECT 'CNE.ESTAB_ORIG' r, COUNT(*) n FROM demanda_cne t LEFT JOIN dim_establecimiento d ON t.ESTAB_ORIG=d.id WHERE t.ESTAB_ORIG IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'CNE.ESTAB_DEST', COUNT(*) FROM demanda_cne t LEFT JOIN dim_establecimiento d ON t.ESTAB_DEST=d.id WHERE t.ESTAB_DEST IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'CNE.E_OTOR_AT', COUNT(*) FROM demanda_cne t LEFT JOIN dim_establecimiento d ON t.E_OTOR_AT=d.id WHERE t.E_OTOR_AT IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'CNE.C_SALIDA', COUNT(*) FROM demanda_cne t LEFT JOIN dim_causal_salida d ON t.C_SALIDA=d.id WHERE t.C_SALIDA IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'CNE.TIPO_PREST', COUNT(*) FROM demanda_cne t LEFT JOIN dim_tipo_lista d ON t.TIPO_PREST=d.id WHERE t.TIPO_PREST IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'CNE.CIE10', COUNT(*) FROM demanda_cne t LEFT JOIN dim_cie10 d ON t.CIE10_HOMOLOGADO=d.codigo WHERE t.CIE10_HOMOLOGADO IS NOT NULL AND d.codigo IS NULL
UNION ALL SELECT 'CNE.PRESTA_MIN', COUNT(*) FROM demanda_cne t LEFT JOIN dim_maestro_prestacion d ON t.PRESTA_MIN=d.codigo WHERE t.PRESTA_MIN IS NOT NULL AND d.codigo IS NULL
UNION ALL SELECT 'IQ.ESTAB_ORIG', COUNT(*) FROM demanda_iq t LEFT JOIN dim_establecimiento d ON t.ESTAB_ORIG=d.id WHERE t.ESTAB_ORIG IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'IQ.ESTAB_DEST', COUNT(*) FROM demanda_iq t LEFT JOIN dim_establecimiento d ON t.ESTAB_DEST=d.id WHERE t.ESTAB_DEST IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'IQ.E_OTOR_AT', COUNT(*) FROM demanda_iq t LEFT JOIN dim_establecimiento d ON t.E_OTOR_AT=d.id WHERE t.E_OTOR_AT IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'IQ.C_SALIDA', COUNT(*) FROM demanda_iq t LEFT JOIN dim_causal_salida d ON t.C_SALIDA=d.id WHERE t.C_SALIDA IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'IQ.TIPO_PREST', COUNT(*) FROM demanda_iq t LEFT JOIN dim_tipo_lista d ON t.TIPO_PREST=d.id WHERE t.TIPO_PREST IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'IQ.CIE10', COUNT(*) FROM demanda_iq t LEFT JOIN dim_cie10 d ON t.CIE10_HOMOLOGADO=d.codigo WHERE t.CIE10_HOMOLOGADO IS NOT NULL AND d.codigo IS NULL
UNION ALL SELECT 'IQ.PRESTA_MIN', COUNT(*) FROM demanda_iq t LEFT JOIN dim_prestacion_cne_iq d ON t.PRESTA_MIN=d.codigo_sigte WHERE t.PRESTA_MIN IS NOT NULL AND d.codigo_sigte IS NULL
UNION ALL SELECT 'PROC.ESTAB_ORIG', COUNT(*) FROM demanda_proc t LEFT JOIN dim_establecimiento d ON t.ESTAB_ORIG=d.id WHERE t.ESTAB_ORIG IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'PROC.ESTAB_DEST', COUNT(*) FROM demanda_proc t LEFT JOIN dim_establecimiento d ON t.ESTAB_DEST=d.id WHERE t.ESTAB_DEST IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'PROC.E_OTOR_AT', COUNT(*) FROM demanda_proc t LEFT JOIN dim_establecimiento d ON t.E_OTOR_AT=d.id WHERE t.E_OTOR_AT IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'PROC.C_SALIDA', COUNT(*) FROM demanda_proc t LEFT JOIN dim_causal_salida d ON t.C_SALIDA=d.id WHERE t.C_SALIDA IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'PROC.TIPO_PREST', COUNT(*) FROM demanda_proc t LEFT JOIN dim_tipo_lista d ON t.TIPO_PREST=d.id WHERE t.TIPO_PREST IS NOT NULL AND d.id IS NULL
UNION ALL SELECT 'PROC.CIE10', COUNT(*) FROM demanda_proc t LEFT JOIN dim_cie10 d ON t.CIE10_HOMOLOGADO=d.codigo WHERE t.CIE10_HOMOLOGADO IS NOT NULL AND d.codigo IS NULL
